}
.co-card__shoe {
  position: relative;
  width: 130%;
  flex-shrink: 0;
  top: -20px;
}
.co-card__shoe-img {
  -webkit-user-select: none;
     -moz-user-select: none;
      -ms-user-select: none;
          user-select: none;
